const express = require('express');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(express.json());

const client = new Client({
  node: 'http://localhost:9200',
});

app.post('/search', (req, res) => {
  const indexName = req.params.index;
  const queryDSL = req.body.query;

  if (!indexName || !queryDSL) {
    return res.status(400).send({ message: 'Index name and query DSL are required' });
  }

  client.search({
    index: indexName,
    body: queryDSL,
  })
    .then((result) => {
      res.send(result.body.hits.hits);
    })
    .catch((error) => {
      console.error(error);
      res.status(500).send({ message: 'Error searching the index' });
    });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});